cd /home/archon/FormalizationProjects/Algebraic-Jacobian-Challenge; python3 - <<'PY'
import re
lines=open('references/kleiman-picard-src/kleiman-picard.tex').read().split('\n')
# counter-sharing envs
shared={'thm','cor','lem','prp','dfn','eg','ex','rmk','sbs'}
sec=0; cnt=0
targets={'th:repDiv','dfn:Abel','lm:ctn','th:main','lm:qt','df:Pfs','df:Psch','cor:algsch','th:Mumford','th:genrep'}
out=[]
for i,l in enumerate(lines,1):
    if re.match(r'\\section\{',l):
        # only count real numbered sections (not commented)
        sec+=1; cnt=0
        out.append(f'SECTION {sec}: {l.strip()[:50]} (L{i})')
        continue
    m=re.match(r'\\begin\{(\w+)\}',l.strip())
    if m and m.group(1) in shared:
        cnt+=1
        lab=re.search(r'\\label\{([^}]+)\}',l)
        labtxt=lab.group(1) if lab else ''
        # also check next line for label
        if not labtxt and i< len(lines):
            lab2=re.search(r'\\label\{([^}]+)\}',lines[i])
            if lab2: labtxt=lab2.group(1)
        num=f'{sec}.{cnt}'
        if labtxt in targets:
            out.append(f'   *** {m.group(1)} {num}  label={labtxt} (L{i})')
        elif labtxt:
            out.append(f'   {m.group(1)} {num}  {labtxt}')
print('\n'.join([o for o in out if 'SECTION' in o or '***' in o or any(s in o for s in ['3.','4.','2.'])][:80]))
